  ('disabled-6f0ba476-moex-00648', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-d3ff7f6b', 'sub-disabled-6f0ba476-07', NULL, 'single_choice', 'A廠商生產10單位產量時的總成本為550元，且生產第11單位產量的邊際 成本為60元。下列何者正確？', '["生產11單位產量時的平均變動成本為45元", "生產11單位產量時的平均總成本為50元", "生產11單位產量時的平均總成本為55.4元", "生產第10單位產量時的邊際成本為55元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "2d98a20a2928", "answer_pdf_sha1": "0f20895e9ec9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
