  ('disabled-6f0ba476-moex-00650', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-d3ff7f6b', 'sub-disabled-6f0ba476-07', NULL, 'single_choice', '有關寡占市場的敘述，下列何者正確？', '["寡占廠商之利潤不僅與自身產量多寡有關，也與其他廠商產量多寡有關", "賽局理論不單運用於寡占市場，也可運用於完全競爭或獨占市場", "如果寡占廠商追求自身利潤極大且彼此不合作，則產業的產量高於完全競 爭水準，且低於獨占水準", "追求自利會使寡占總產量大於獨占產量，甚至有可能大於完全競爭產量"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "2d98a20a2928", "answer_pdf_sha1": "0f20895e9ec9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
